const input = $input.first().json;
const body = input.body || input;

const chatId = String(body.telegram_chat_id || '').trim();
const botToken = String(body.telegram_bot_token || '').trim();

let text = '';
if (typeof body.telegram_text === 'string') {
  text = body.telegram_text;
} else if (body.telegram_message && typeof body.telegram_message.message === 'string') {
  text = body.telegram_message.message;
} else if (body.unified_agenda) {
  const agenda = body.unified_agenda;
  text = `Daily agenda for ${agenda.date || body.agenda_date}: ${agenda.stats?.total_count || 0} items.`;
}

text = String(text || `Daily agenda for ${body.agenda_date}: no message generated.`);

if (!botToken) {
  throw new Error('Missing telegram_bot_token in webhook payload. Save the bot token in backend DB and pass it from FastAPI.');
}
if (!chatId) {
  throw new Error('Missing telegram_chat_id in webhook payload. Connect Telegram chat_id first.');
}
if (!text.trim()) {
  throw new Error('Telegram message text is empty.');
}

return [{
  json: {
    status: 'prepared',
    source: 'n8n_telegram_daily_agenda',
    user_id: body.user_id,
    user_email: body.user_email,
    agenda_date: body.agenda_date,
    bot_token: botToken,
    chat_id: chatId,
    text
  }
}];

const telegramResponse = $input.first().json;
return [{
  json: {
    status: 'sent',
    source: 'n8n_telegram_daily_agenda',
    telegram_response: telegramResponse
  }
}];
